import{_ as i,M as n,p as r,q as s,R as e,t,N as a,a1 as l}from"./framework-96b046e1.js";const h={},m=e("h1",{id:"dramatically-increase-your-productivity-with-atomic-git-commits",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#dramatically-increase-your-productivity-with-atomic-git-commits","aria-hidden":"true"},"#"),t(" Dramatically increase your productivity with Atomic Git Commits")],-1),c=e("p",null,[e("em",null,"Atomic: of or forming a single irreducible unit or component in a larger system.")],-1),u={href:"https://dev.to/samuelfaure/how-atomic-git-commits-dramatically-increased-my-productivity-and-will-increase-yours-too-4a84",target:"_blank",rel:"noopener noreferrer"},d=e("h2",{id:"knowing-vs-actually-knowing",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#knowing-vs-actually-knowing","aria-hidden":"true"},"#"),t(" Knowing VS Actually Knowing")],-1),p=e("p",null,"I remember when my first mentor told me about Test-Driven Development. A great methodological approach to software engineering. It took me just a few minutes to understand what it was and how it worked.",-1),y=e("p",null,"Then I spent the next six months actively not practicing it. TDD is hard when you start, so you just... don't.",-1),g=e("p",null,"Half a year later, I was hitting my head against a wall trying to build a new feature. I forced myself for the first time to actually do TDD by the book. The wall that was blocking my progress disappeared instantly.",-1),w={href:"https://suchdevblog.com/opinions/WhyOurWorkCultureSucks.html",target:"_blank",rel:"noopener noreferrer"},b=l('<p>This long introduction is here to illustrate a point: you can <em>know</em> what you should do, but you might not know how important it is to <em>actually do it</em>. So many people out there, just like I did before, know how TDD is great... yet still don&#39;t use it.</p><p>The simplest concepts can often completely change the way you work... if you would only apply them. Introducing: the atomic git commits.</p><h2 id="what-s-an-atomic-git-commit" tabindex="-1"><a class="header-anchor" href="#what-s-an-atomic-git-commit" aria-hidden="true">#</a> What&#39;s an atomic git commit?</h2><p>Working with atomic git commits means your commits are of the smallest possible size. Each commit does one, and only one simple thing, that can be summed up in a simple sentence.</p><p>The amount of code change doesn&#39;t matter. It can be a letter or it can be a hundred thousand lines, but you should be able to describe the change with one simple short sentence.</p><p>Ideally, you also want your test suite to be in the green when you commit. Your changes might be &quot;atomic&quot;, i.e the smallest possible, but they should also be &quot;complete&quot;, which means your test suite always follow through.</p><p>As small as possible, but complete: this is an atomic git commit.</p><h2 id="why-should-you-write-atomic-git-commits" tabindex="-1"><a class="header-anchor" href="#why-should-you-write-atomic-git-commits" aria-hidden="true">#</a> Why should you write atomic git commits?</h2><p>There are a few great advantages to practicing atomic git commits, and we&#39;ll briefly detail them. But the last one really is the most important. It might completely change the way you approach your work, increase your productivity by an order of magnitude, and make your job much more enjoyable.</p><h3 id="reason-number-1-an-atomic-change-is-a-reversible-change" tabindex="-1"><a class="header-anchor" href="#reason-number-1-an-atomic-change-is-a-reversible-change" aria-hidden="true">#</a> Reason number 1: An atomic change is a reversible change</h3><p>We all know this simple truth about software: the requirements are <em>always</em> changing. By writing atomic git commits, we allow ourselves to revert any changes by a simple commit revert. This already increases your productivity tremendously.</p><h3 id="reason-number-2-a-clean-git-history" tabindex="-1"><a class="header-anchor" href="#reason-number-2-a-clean-git-history" aria-hidden="true">#</a> Reason number 2: A clean git history</h3><p>When shit hit the fan, a clean git history means the difference between pain and salvation. It&#39;s like insuring your house: seems useless, until there&#39;s a fire.</p><h3 id="reason-number-3-pull-requests-are-much-easier-to-review" tabindex="-1"><a class="header-anchor" href="#reason-number-3-pull-requests-are-much-easier-to-review" aria-hidden="true">#</a> Reason number 3: Pull requests are much easier to review</h3><p>Your team will absolutely love you for this.</p><h3 id="reason-number-4-a-much-much-better-workflow" tabindex="-1"><a class="header-anchor" href="#reason-number-4-a-much-much-better-workflow" aria-hidden="true">#</a> Reason number 4: A much, much better workflow</h3><p>This is by far the most important reason to practice atomic git commits: it completely alters the way you approach problem-solving.</p><p>If you&#39;re like me, you might have a tendency while developing a feature, to just... <em>do it</em>. Entirely.</p><p>Then you realize how you did not think everything through.</p><p>You need to change more that you expected. Some edge cases aren&#39;t taken into account. You broke some unrelated tests, they need fixing. Soon, you end up in a maze of your own making. You&#39;re lost. Your head hurts. You can&#39;t make any progress without being entirely focused.</p><p>Now, this is the <em>wrong</em> way to do things. And worse, you already know the <em>right</em> way, because it&#39;s so obvious.</p><p>The well-known method to complete a big, complex task: cut it down into smaller, manageable, tiny steps. Each step -its own simple problem to solve. This is obvious advice that you probably already heard many times... But are you actually practicing it in your daily job?</p><p>Well, here&#39;s a great way to actually practice it: write atomic git commits.</p><p>By forcefully working in atomic commits, you&#39;re approaching the work the right way, by simplifying it into smaller steps. After all, <em>simplifying complexity</em> is the very core of our job. So why aren&#39;t we always consciously doing it?</p><p>Of course this advice might sound obvious. But if my past experience proves anything, it&#39;s that the obvious really bears repeating, and even more importantly, it bears <em>practicing</em>.</p><p>Make your work simpler, better, more manageable, and most importantly: <em>make it easier</em>. Take small steps. Write small commits. Atomic commits. You will love them.</p>',26);function f(k,v){const o=n("ExternalLinkIcon");return r(),s("div",null,[m,c,e("p",null,[e("em",null,[t("This article was first published on "),e("a",u,[t("Dev.to"),a(o)]),t(". Thanks to the team for choosing it as a Top 7 weekly!")])]),d,p,y,g,e("p",null,[e("a",w,[t("In a previous article"),a(o)]),t(", I explained how many managers and tech leads often know exactly how to make our industry better... yet don't. There is always a good reason to not do things right. And somehow we still end up surprised when we're doing things wrong.")]),b])}const x=i(h,[["render",f],["__file","AtomicGitCommits.html.vue"]]);export{x as default};
